#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
using namespace std;

struct Student
{
    string name;
    int grade;
};

int main()
{
    vector<Student> students = {
        {"Ahmet", 85},
        {"Ayse", 92},
        {"Mehmet", 67},
        {"Zeynep", 78},
        {"Can", 55}
    };

    cout << "Tum ogrenciler:" << endl;
    for (const auto& s : students)
    {
        cout << s.name << ": " << s.grade << endl;
    }

    // Yeni ogrenci ekleme
    students.push_back({"Elif", 88});
    cout << "\nElif eklendi. Toplam ogrenci: " << students.size() << endl;

    // Not güncelleme
    for (auto& s : students)
    {
        if (s.name == "Mehmet")
        {
            s.grade = 70;
            cout << "\nMehmet'in notu guncellendi: " << s.grade << endl;
        }
    }

    // Geçenler / kalanlar sayısı
    int passing = 0, failing = 0;
    for (const auto& s : students)
    {
        if (s.grade >= 60) passing++;
        else failing++;
    }

    cout << "\nGecen ogrenci sayisi: " << passing << endl;
    cout << "Kalan ogrenci sayisi: " << failing << endl;

    // Sıralama (en yüksekten en düşüğe)
    sort(students.begin(), students.end(), [](const Student& a, const Student& b) {
        return a.grade > b.grade;
    });

    cout << "\nNot siralamasi (yuksekten alcaga):" << endl;
    for (const auto& s : students)
    {
        cout << s.name << ": " << s.grade << endl;
    }

    // Ortalama
    double total = 0;
    for (const auto& s : students) total += s.grade;
    cout << "\nSinif ortalamasi: " << (total / students.size()) << endl;

    return 0;
}
